pub struct RegionMetadataView { pub region_size: u64, pub log_area_len: u64, pub log_id: u128 }

impl View for RegionMetadata {
    type V = RegionMetadataView;
    closed spec fn view(&self) -> RegionMetadataView {
        RegionMetadataView { region_size: self.region_size, log_area_len: self.log_area_len, log_id: self.log_id }
    }
}
